import{_ as t,o as e,c as d,e as a}from"./app-58c21a21.js";const r={},l=a('<h2 id="computed" tabindex="-1"><a class="header-anchor" href="#computed" aria-hidden="true">#</a> computed</h2><p>每个计算属性内部维护一个dirty，第一次调用默认为true，存在一个变量this.value,随后将其设置为false，再次调用就不会执行。</p><p>当依赖的属性值变化是就触发更新，把dirty设置为true，页面重新更新，重新获取最新的值。</p><table><thead><tr><th style="text-align:center;"></th><th style="text-align:center;">computed</th><th style="text-align:center;">watch</th></tr></thead><tbody><tr><td style="text-align:center;">缓存</td><td style="text-align:center;">有缓存，调用多次相同的只执行一次</td><td style="text-align:center;">无缓存，调用多少次就执行多少次</td></tr><tr><td style="text-align:center;">是否支持异步</td><td style="text-align:center;">否</td><td style="text-align:center;">是</td></tr><tr><td style="text-align:center;">如何选择</td><td style="text-align:center;">计算的值多次使用，某个数据导致这个值重新计算（一个值由多个数据组成）</td><td style="text-align:center;">监听某个值变化进行函数调用（一个值影响多个数据）</td></tr></tbody></table><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><ol><li>computed可以做的，watch也可以做，反之不行</li><li>从使用场景上说，computed适用一个数据被多个数据影响，而watch适用于一个数据影响多个数据</li></ol>',6),c=[l];function n(i,h){return e(),d("div",null,c)}const o=t(r,[["render",n],["__file","WatchheComputeddequbie.html.vue"]]);export{o as default};
